namespace batt {

//=#=#==#==#===============+=+=+=+=++=++++++++++++++-++-+--+-+----+---------------
template <usize kStaticSize, usize kDynamicSize>
class BasicStableStringStore
{
   public:
    using Self = BasicStableStringStore;

    static constexpr usize kUnitSizeLog2 = 6;

    static constexpr usize kUnitSize = usize{1} << kUnitSizeLog2;

    using StorageUnit = std::aligned_storage_t<kUnitSize, kUnitSize>;

    static constexpr usize kDefaultMinParallelCopySize = 64 * 1024;

    static const usize kStaticSizeLog2 = std::max<usize>(kUnitSizeLog2,  //
                                                         batt::log2_ceil(kStaticSize));

    static const usize kDynamicSizeLog2 = std::max<usize>(kUnitSizeLog2,  //
                                                          batt::log2_ceil(kDynamicSize));

    static const usize kStaticAllocSize = usize{1} << kStaticSizeLog2;
    static const usize kDynamicAllocSize = usize{1} << kDynamicSizeLog2;

    static const usize kStaticAllocUnitsLog2 = (kStaticSizeLog2 - kUnitSizeLog2);
    static const usize kDynamicAllocUnitsLog2 = (kDynamicSizeLog2 - kUnitSizeLog2);

    static const usize kStaticAllocUnits = usize{1} << kStaticAllocUnitsLog2;
    static const usize kDynamicAllocUnits = usize{1} << kDynamicAllocUnitsLog2;

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    class AbstractDestructible
    {
       public:
        AbstractDestructible(const AbstractDestructible&) = delete;

        AbstractDestructible& operator=(const AbstractDestructible&) = delete;

        virtual ~AbstractDestructible() = default;

        AbstractDestructible* next = nullptr;

       protected:
        AbstractDestructible() = default;
    };

    template <typename T>
    class Destructible : public AbstractDestructible
    {
       public:
        explicit Destructible() : obj_{}
        {
        }

        template <typename... Args, typename = EnableIfNoShadow<Destructible, Args...>>
        explicit Destructible(Args&&... args) : obj_(BATT_FORWARD(args)...)
        {
        }

        T* get()
        {
            return &this->obj_;
        }

       private:
        T obj_;
    };

    template <typename T>
    class DestructibleArray : public AbstractDestructible
    {
       public:
        template <typename... Args>
        explicit DestructibleArray(usize n, Args&&... args) : n_{n}
        {
            T* a = this->get();
            for (usize i = 0; i < this->n_; ++i) {
                new (&a[i]) T(args...);
            }
        }

        ~DestructibleArray() noexcept
        {
            T* a = this->get();
            for (usize i = this->n_; i > 0;) {
                --i;
                a[i].~T();
            }
        }

        T* get()
        {
            return reinterpret_cast<T*>(&this->first_);
        }

       private:
        usize n_;
        std::aligned_storage_t<sizeof(T), alignof(T)> first_;
    };

    //+++++++++++-+-+--+----- --- -- -  -  -   -

    BasicStableStringStore();

    BasicStableStringStore(const BasicStableStringStore&) = delete;
    BasicStableStringStore& operator=(const BasicStableStringStore&) = delete;

    ~BasicStableStringStore() noexcept
    {
        // Destruct the constructed objects, in reverse-construction order.
        //
        while (this->first_d_) {
            auto* d = this->first_d_;
            this->first_d_ = d->next;
            d->~AbstractDestructible();
        }
    }

    MutableBuffer allocate(usize n);

    std::string_view store(const std::string_view& s,
                           batt::WorkerPool& worker_pool = batt::WorkerPool::null_pool(),
                           Optional<usize> opt_min_parallel_copy_size = None);

    ConstBuffer store(const ConstBuffer& buffer,
                      batt::WorkerPool& worker_pool = batt::WorkerPool::null_pool(),
                      Optional<usize> opt_min_parallel_copy_size = None)
    {
        const std::string_view s =
            this->store(std::string_view{static_cast<const char*>(buffer.data()), buffer.size()}, worker_pool,
                        opt_min_parallel_copy_size);

        return ConstBuffer{s.data(), s.size()};
    }

    template <typename... Parts>
    ConstBuffer concat(Parts&&... parts)
    {
        usize total_size = 0;

        // Compute the total amount of memory needed to be allocated for the result of the
        // concatenation.
        //
        const auto add_to_total = [&total_size](auto&& part) {
            total_size += batt::as_const_buffer(part).size();
            return 0;
        };

        (add_to_total(parts), ...);

        MutableBuffer mbuf = this->allocate(total_size);
        MutableBuffer cbuf = mbuf;

        // Copy each part to memory.
        //
        const auto copy_part = [&mbuf](auto&& part) {
            auto src = batt::as_const_buffer(part);
            std::memcpy(mbuf.data(), src.data(), src.size());
            mbuf += src.size();
            return 0;
        };

        (copy_part(parts), ...);

        return cbuf;
    }

    template <typename T, typename... Args>
    T* construct(StaticType<T>, Args&&... args)
    {
        MutableBuffer buffer = this->allocate(sizeof(Destructible<T>));

        Destructible<T>* d = new (buffer.data()) Destructible<T>{BATT_FORWARD(args)...};

        d->next = this->first_d_;
        this->first_d_ = d;

        return d->get();
    }

    template <typename T, typename... Args>
    Slice<T> construct_array(StaticType<T> elem, usize n, Args&&... args)
    {
        if (n == 0) {
            return {nullptr, nullptr};
        }

        if (n == 1) {
            return as_slice(this->construct(elem, BATT_FORWARD(args)...), 1);
        }

        MutableBuffer buffer = this->allocate(
            sizeof(DestructibleArray<T>) + sizeof(std::aligned_storage_t<sizeof(T), alignof(T)>) * (n - 1));

        DestructibleArray<T>* d = new (buffer.data()) DestructibleArray<T>{n, BATT_FORWARD(args)...};

        d->next = this->first_d_;
        this->first_d_ = d;

        return as_slice(d->get(), n);
    }

   private:
    AbstractDestructible* first_d_ = nullptr;

    std::array<StorageUnit, kStaticAllocUnits> chunk0_;

    std::vector<std::unique_ptr<StorageUnit[]>> chunks_;

    MutableBuffer free_chunk_;
};

using StableStringStore = BasicStableStringStore<64, 4096>;

//#=##=##=#==#=#==#===#+==#+==========+==+=+=+=+=+=++=+++=+++++=-++++=-+++++++++++

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <usize kStaticSize, usize kDynamicSize>
BasicStableStringStore<kStaticSize, kDynamicSize>::BasicStableStringStore()
    : free_chunk_{std::addressof(this->chunk0_), sizeof(this->chunk0_)}
{
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <usize kStaticSize, usize kDynamicSize>
MutableBuffer BasicStableStringStore<kStaticSize, kDynamicSize>::allocate(usize n)
{
    // Check if the current free_chunk_ is large enough to hold n bytes. If it isn't, we need to
    // dynamically allocate a new chunk.
    //
    if (this->free_chunk_.size() < n) {
        // Allocate new chunk, add it to the list of dynamically allocated chunks, and point free_chunk_
        // to this new chunk.
        //
        const usize new_chunk_size = batt::round_up_bits(kDynamicSizeLog2, n);
        const usize n_units = new_chunk_size >> kUnitSizeLog2;
        std::unique_ptr<StorageUnit[]> new_chunk{new StorageUnit[n_units]};
        char* const new_chunk_data = (char*)new_chunk.get();
        this->chunks_.emplace_back(std::move(new_chunk));
        this->free_chunk_ = MutableBuffer{new_chunk_data, new_chunk_size};
    }

    BATT_CHECK_GE(this->free_chunk_.size(), n);

    // Return the newly allocated chunk and advance the start of the free_chunk_ buffer by n bytes to
    // indicate that this region of memory is now occupied.
    //
    MutableBuffer stable_buffer{this->free_chunk_.data(), n};
    this->free_chunk_ += n;
    return stable_buffer;
}

//==#==========+==+=+=++=+++++++++++-+-+--+----- --- -- -  -  -   -
//
template <usize kStaticSize, usize kDynamicSize>
std::string_view BasicStableStringStore<kStaticSize, kDynamicSize>::store(
    const std::string_view& s, batt::WorkerPool& worker_pool, Optional<usize> opt_min_parallel_copy_size)
{
    const usize min_parallel_copy_size =
        opt_min_parallel_copy_size.value_or(Self::kDefaultMinParallelCopySize);

    // Allocate a buffer the size of the input string data.
    //
    MutableBuffer stable_buffer = this->allocate(s.size());

    BATT_CHECK_EQ(stable_buffer.size(), s.size());

    // Check if we would benefit from parallelizing the copying process. If we do have workers in the
    // worker_pool and the size of the string data isn't too small, parallelize.
    //
    if (worker_pool.size() == 0 || s.size() < min_parallel_copy_size) {
        std::memcpy(stable_buffer.data(), s.data(), s.size());
    } else {
        batt::ScopedWorkContext work_context{worker_pool};

        const batt::TaskCount max_tasks{worker_pool.size() + 1};
        const batt::TaskSize min_task_size{min_parallel_copy_size};

        const char* const src_begin = s.data();
        const char* const src_end = src_begin + s.size();
        char* const dst_begin = static_cast<char*>(stable_buffer.data());

        batt::parallel_copy(work_context, src_begin, src_end, dst_begin, min_task_size, max_tasks);
    }

    // Return the copy.
    //
    return std::string_view{static_cast<const char*>(stable_buffer.data()), stable_buffer.size()};
}

}  // namespace batt
